// ============================================================
// DOMAIN FILTER & EMAIL CLASSIFICATION
// ============================================================
// Customize this node for your specific use case
// ============================================================

const json = $input.item.json;
const subject = json.subject || json.Subject || '';
const snippet = json.snippet || '';
const fromRaw = json.from || json.From || '';
const fromText = typeof fromRaw === 'object' ? (fromRaw.text || JSON.stringify(fromRaw)) : String(fromRaw);
const text = (subject + ' ' + snippet + ' ' + fromText).toLowerCase();

// ============================================================
// STEP 1: Configure your allowed domains
// ============================================================
// Add the domains you want to monitor (without @ symbol)
// Example: ['company.com', 'partner.co.jp', 'supplier.net']
const allowedDomains = [
  // Add your domains here
  // 'example.com',
  // 'example.co.jp',
];

// Check if email is from an allowed domain
const fromLower = fromText.toLowerCase();
const isFromAllowedDomain = allowedDomains.length === 0 || allowedDomains.some(d => fromLower.includes(d));

// ============================================================
// STEP 2: Configure classification keywords
// ============================================================

// Category A keywords (e.g., Cancellations, Deletions)
const categoryAKeywords = [
  // Add your Category A keywords here
  // 'cancel', 'cancelled', 'delete', 'remove'
];

// Category B keywords (e.g., Updates, Changes)
const categoryBKeywords = [
  // Add your Category B keywords here
  // 'update', 'change', 'modify', 'reschedule'
];

// Category C keywords (e.g., New items - this is the default)
const categoryCKeywords = [
  // Add your Category C keywords here (optional)
  // 'new', 'offer', 'proposal', 'available'
];

// ============================================================
// STEP 3: Configure identifier codes (optional)
// ============================================================
// If your emails contain specific codes like [ABC] or 【XYZ】
const identifierCodes = [
  // Add your identifier codes here (lowercase)
  // 'abc', 'xyz', 'code1'
];

// Normalize full-width characters to ASCII
const normalizeAscii = value => String(value || '').replace(/[Ａ-Ｚ０-９]/g, ch => String.fromCharCode(ch.charCodeAt(0) - 0xFEE0));
const textUpper = normalizeAscii(subject + ' ' + snippet + ' ' + fromText).toUpperCase();

// Check for identifier codes in brackets
const hasIdentifierCode = identifierCodes.some(c => 
  textUpper.includes('【' + c.toUpperCase() + '】') || 
  textUpper.includes('[' + c.toUpperCase() + ']')
);

// ============================================================
// Classification Logic
// ============================================================

// Skip if not from allowed domain and no identifier match
if (!isFromAllowedDomain && !hasIdentifierCode) {
  return { json: { _skip: true } };
}

// Check if email matches any category keywords
const isCategoryA = categoryAKeywords.some(k => text.includes(k.toLowerCase()));
const isCategoryB = categoryBKeywords.some(k => text.includes(k.toLowerCase()));
const hasCategoryC = categoryCKeywords.length === 0 || categoryCKeywords.some(k => text.includes(k.toLowerCase()));

// If no keywords configured and domain doesn't match, skip
if (categoryAKeywords.length === 0 && categoryBKeywords.length === 0 && categoryCKeywords.length === 0) {
  // Process all emails from allowed domains when no keywords configured
  if (!isFromAllowedDomain) {
    return { json: { _skip: true } };
  }
}

// Determine email type/category
let emailType = 'CategoryC'; // Default
if (isCategoryA) emailType = 'CategoryA';
else if (isCategoryB) emailType = 'CategoryB';

return { json: { ...json, _skip: false, _email_type: emailType } };

// ============================================================
// FILE TYPE DETECTION
// ============================================================
// Identifies attachment types and preserves metadata
// ============================================================

const item = $input.item;
const binary = item.binary || {};
const json = item.json;

const subject = json.Subject || json.subject || '';
const fromData = json.From || json.from || '';

let emailType = json._email_type || '';
if (!emailType) {
  try {
    const currentId = json.id;
    const filteredItems = $('Filter Valid Emails').all();
    for (const f of filteredItems) {
      if (f.json.id === currentId && f.json._email_type) {
        emailType = f.json._email_type;
        break;
      }
    }
  } catch(e) {}
}
emailType = emailType || 'CategoryC';

let fileInfo = { excel: null, pptx: null, pdf: null, image: null };
let attachments = [];

for (const key of Object.keys(binary)) {
  const bin = binary[key];
  if (!bin || !bin.fileName) continue;
  const fn = bin.fileName.toLowerCase();
  const mime = (bin.mimeType || '').toLowerCase();
  attachments.push({ filename: bin.fileName, mimeType: bin.mimeType, key: key });

  if (fn.endsWith('.xlsx') || fn.endsWith('.xls')) fileInfo.excel = { key, fileName: bin.fileName };
  else if (fn.endsWith('.pptx') || fn.endsWith('.ppt')) fileInfo.pptx = { key, fileName: bin.fileName };
  else if (fn.endsWith('.pdf') || mime.includes('pdf')) fileInfo.pdf = { key, fileName: bin.fileName };
  else if (fn.endsWith('.png') || fn.endsWith('.jpg') || fn.endsWith('.jpeg') || mime.startsWith('image/')) fileInfo.image = { key, fileName: bin.fileName, mimeType: bin.mimeType || 'image/png' };
}

// Variable format types need GPT Vision even for Excel
const isVariableFormat = emailType === 'CategoryA' || emailType === 'CategoryB';
const hasExcelDirect = fileInfo.excel !== null && !isVariableFormat;
const hasFileConvert = fileInfo.pptx !== null || fileInfo.pdf !== null || (fileInfo.excel !== null && isVariableFormat);

let convType = null, convKey = null;
if (fileInfo.pptx) { convType = 'pptx'; convKey = fileInfo.pptx.key; }
else if (fileInfo.pdf) { convType = 'pdf'; convKey = fileInfo.pdf.key; }
else if (fileInfo.excel && isVariableFormat) { convType = 'xlsx'; convKey = fileInfo.excel.key; }

const output = {
  ...json,
  id: json.id,
  Subject: subject,
  subject: subject,
  From: fromData,
  from: fromData,
  attachments: attachments,
  has_excel: hasExcelDirect,
  has_pptx_pdf: hasFileConvert,
  has_image: fileInfo.image !== null,
  excel_binary_key: fileInfo.excel ? fileInfo.excel.key : null,
  conversion_type: convType,
  conversion_binary_key: convKey,
  image_binary_key: fileInfo.image ? fileInfo.image.key : null,
  _email_type: emailType
};

return {
  json: output,
  binary: item.binary
};

// ============================================================
// EXCEL DATA EXTRACTION
// ============================================================
// Customize this node to parse your specific Excel format
// ============================================================

// Map codes to full names (customize for your use case)
const codeToNameMap = {
  // 'CODE1': 'Full Name 1',
  // 'CODE2': 'Full Name 2',
};

function excelTimeToHHMM(fraction) {
  if (!fraction && fraction !== 0) return '';
  const totalMinutes = Math.round(fraction * 24 * 60);
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  return String(hours).padStart(2, '0') + ':' + String(minutes).padStart(2, '0');
}

let excelSourceItems = [];
try { excelSourceItems = $('IF - Has Excel?').all(); } catch(e) {}

const allRows = $input.all().map(i => i.json);
const results = [];

let hintYear = new Date().getFullYear();
let hintMonth = new Date().getMonth() + 1;
let currentName = '';
let currentType = 'Regular';

const dataBySource = {};

for (const row of allRows) {
  const allText = JSON.stringify(row);
  const firstKey = Object.keys(row)[0] || '';
  const firstVal = row[firstKey] || '';

  // Extract year/month from text (customize pattern as needed)
  const ymMatch = allText.match(/(20\d{2})[-\/年]\s*(\d{1,2})/);
  if (ymMatch) {
    hintYear = parseInt(ymMatch[1]);
    hintMonth = parseInt(ymMatch[2]);
  }

  // Extract source name from brackets (customize pattern as needed)
  const nameMatch = allText.match(/【([A-Z]+)[^】]*】/i);
  if (nameMatch) {
    const code = nameMatch[1].toUpperCase();
    currentName = codeToNameMap[code] || code;
  }

  // Check for codes in the text
  for (const code of Object.keys(codeToNameMap)) {
    if (allText.toUpperCase().includes(code)) {
      currentName = codeToNameMap[code] || code;
      break;
    }
  }

  // Skip header rows (customize as needed)
  if (allText.includes('Header1') && allText.includes('Header2')) continue;

  // ============================================================
  // CUSTOMIZE: Add your Excel parsing logic here
  // ============================================================

  // Example: Parse rows with specific structure
  if (row.__EMPTY_1 !== undefined && typeof row.__EMPTY_1 === 'number') {
    const startTime = typeof row.__EMPTY_2 === 'number'
      ? excelTimeToHHMM(row.__EMPTY_2)
      : excelTimeToHHMM(row.__EMPTY_1);
    const endTime = typeof row.__EMPTY_4 === 'number'
      ? excelTimeToHHMM(row.__EMPTY_4)
      : excelTimeToHHMM(row.__EMPTY_2);

    if (startTime) {
      const sourceName = currentName || 'Unknown';
      const amount = typeof row.__EMPTY_7 === 'number' ? row.__EMPTY_7 : (row.__EMPTY_5 || 0);
      const dataItem = {
        date: hintYear + '-' + String(hintMonth).padStart(2,'0') + '-' + String(row.__EMPTY_1).padStart(2,'0'),
        day_of_week: firstVal,
        start_time: startTime,
        end_time: endTime,
        amount: amount,
        type: currentType,
        name: '',
        source_name: sourceName
      };
      if (!dataBySource[sourceName]) dataBySource[sourceName] = [];
      dataBySource[sourceName].push(dataItem);
    }
  }
}

// Build results
for (const srcItem of excelSourceItems) {
  const meta = srcItem.json;
  const emailId = meta.id || '';
  const emailType = meta._email_type || 'CategoryC'; 

  let defaultSource = '';
  const subjectText = (meta.Subject || meta.subject || '');
  const sourceMatch = subjectText.match(/【([A-Za-z]+)】/i);
  if (sourceMatch) defaultSource = codeToNameMap[sourceMatch[1].toUpperCase()] || sourceMatch[1].toUpperCase();

  let dataForEmail = dataBySource[defaultSource] || [];

  if (!defaultSource && dataForEmail.length == 0) {
    const allSources = Object.keys(dataBySource);
    if (allSources.length === 1) {
      dataForEmail = dataBySource[allSources[0]] || [];
    } else if (allSources.length > 1) {
      dataForEmail = allSources.flatMap(name => dataBySource[name] || []);
    }
  }

  results.push({
    json: {
      _meta_subject: meta.Subject || meta.subject,
      _meta_from: meta.from || meta.From,
      _meta_id: emailId,
      email_id: emailId, 
      _meta_source_name: defaultSource,
      _email_type: emailType,
      choices: [{ message: { content: JSON.stringify(dataForEmail.length ? dataForEmail : [{notes: '⚠️No data found'}]) } }]
    }
  });
}

return results.length ? results : [{ json: { _no_data: true } }];

// ============================================================
// PREPARE IMAGES FOR S3 UPLOAD
// ============================================================

const allItems = $input.all();
const results = [];

let pptxPdfItems = [];
try {
  const allFileItems = $('Detect File Types').all();
  pptxPdfItems = allFileItems.filter(item => item.json.has_pptx_pdf === true);
} catch(e) {}

let filterItems = [];
try { filterItems = $('Filter Valid Emails').all(); } catch(e) {}

for (let idx = 0; idx < allItems.length; idx++) {
  const item = allItems[idx];
  const response = item.json;

  let emailId='', subject='', fromData='', attachments=[], emailType='';

  if (pptxPdfItems[idx]) {
    const meta = pptxPdfItems[idx].json;
    emailId = meta.id || '';
    subject = meta.Subject || '';
    fromData = meta.From || '';
    attachments = meta.attachments || [];
    emailType = meta._email_type || '';
  }

  if (!emailType && emailId) {
    for (const f of filterItems) {
      if (f.json.id === emailId && f.json._email_type) {
        emailType = f.json._email_type;
        break;
      }
    }
  }
  emailType = emailType || 'CategoryC';

  if (response.Files && response.Files.length > 0) {
    const maxPages = Math.min(response.Files.length, 15);
    const ts = Date.now();

    for (let i = 0; i < maxPages; i++) {
      const fileData = response.Files[i];
      if (fileData && fileData.FileData) {
        const fileName = 'convert-' + emailId + '-page-' + (i+1) + '-' + ts + '.png';
        results.push({
          json: {
            _meta_subject: subject,
            _meta_from: fromData,
            _meta_id: emailId,
            _meta_attachments: attachments,
            _meta_process_type: 'pptx_pdf',
            _email_type: emailType,
            _page_index: i,
            _page_filename: fileName,
            _total_pages: maxPages
          },
          binary: {
            data: {
              data: fileData.FileData,
              mimeType: 'image/png',
              fileName: fileName,
              fileExtension: 'png'
            }
          }
        });
      }
    }
  }
}

if (results.length === 0) return [{ json: { _skip: true } }];
return results;

// ============================================================
// COLLECT S3 URLs FOR GPT VISION
// ============================================================

let prepItems = [];
try { prepItems = $('Prepare for S3 Upload').all(); } catch(e) {}

const bucket = $vars.S3_BUCKET_NAME || 'your-bucket-name';
const region = $vars.AWS_REGION || 'us-east-1';
const emailGroups = new Map();

for (const prep of prepItems) {
  const p = prep.json;
  const emailId = p._meta_id || '';
  const filename = p._page_filename || '';
  if (!emailId || !filename) continue;

  const s3Url = 'https://' + bucket + '.s3.' + region + '.amazonaws.com/' + filename;

  if (!emailGroups.has(emailId)) {
    emailGroups.set(emailId, {
      subject: p._meta_subject || '',
      from: p._meta_from || '',
      emailId: emailId,
      attachments: p._meta_attachments || [],
      emailType: p._email_type || 'CategoryC',
      sourceName: p._meta_source_name || '',
      urls: []
    });
  }
  emailGroups.get(emailId).urls.push({ url: s3Url, index: p._page_index || 0 });
}

const results = [];
for (const [emailId, data] of emailGroups) {
  data.urls.sort((a, b) => a.index - b.index);
  results.push({
    json: {
      _meta_subject: data.subject,
      _meta_from: data.from,
      _meta_id: data.emailId,
      _meta_attachments: data.attachments,
      _meta_source_name: data.sourceName,
      _email_type: data.emailType,
      _s3_urls: data.urls.map(u => u.url)
    }
  });
}

if (results.length === 0) return [{ json: { _skip: true } }];
return results;

// ============================================================
// PREPARE GPT VISION REQUEST FOR PPTX/PDF
// ============================================================
// Customize the system prompt and extraction fields
// ============================================================

// Map codes to full names (customize for your use case)
const codeToNameMap = {
  // 'CODE1': 'Full Name 1',
  // 'CODE2': 'Full Name 2',
};

const item = $input.item.json;
const subject = item._meta_subject || '';
const emailId = item._meta_id || '';
const s3Urls = item._s3_urls || [];
const emailType = item._email_type || 'CategoryC';

// Extract source name from subject
const sourceMatch = subject.match(/【([A-Za-z]+)】/i);
const sourceCode = sourceMatch ? sourceMatch[1].toUpperCase() : '';
const sourceName = codeToNameMap[sourceCode] || sourceCode;

// Build prompt based on email type
let prompt = '';
if (emailType === 'CategoryA') {
  prompt = 'Subject: ' + subject + '\n\nThis is a CANCELLATION notice. Extract cancellation details.';
} else if (emailType === 'CategoryB') {
  prompt = 'Subject: ' + subject + '\n\nThis is an UPDATE notice. Extract the changes.';
} else {
  prompt = 'Subject: ' + subject + '\n\nExtract all relevant information from this image.';
}

let userContent = [{ type: 'text', text: prompt }];
for (const url of s3Urls) {
  userContent.push({ type: 'image_url', image_url: { url: url, detail: 'high' } });
}

// ============================================================
// CUSTOMIZE: Update the system prompt and fields for your use case
// ============================================================
const systemPrompt = `You are a data extraction expert. Extract structured information accurately from images.

【Fields to extract】
- date (YYYY-MM-DD format)
- day_of_week
- start_time (HH:MM format)
- end_time (HH:MM format)
- source_code
- name
- amount (numbers only)
- category
- type
- notes

【Output】JSON array only, no explanation`;

const gptBody = {
  model: 'gpt-4o',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userContent }
  ],
  max_tokens: 4096,
  temperature: 0.1
};

return {
  json: {
    _meta_subject: subject,
    _meta_from: item._meta_from,
    _meta_id: emailId,
    _meta_attachments: item._meta_attachments || [],
    _meta_process_type: 'pptx_pdf',
    _meta_source_name: sourceName,
    _email_type: emailType,
    gpt_request_body: JSON.stringify(gptBody)
  }
};

// ============================================================
// PREPARE IMAGE METADATA FOR S3 UPLOAD
// ============================================================

const item = $input.item;
const json = item.json;
const subject = json.Subject || '';
const emailId = json.id || 'unknown';

let emailType = json._email_type || '';
if (!emailType && emailId) {
  try {
    const filteredItems = $('Filter Valid Emails').all();
    for (const f of filteredItems) {
      if (f.json.id === emailId && f.json._email_type) {
        emailType = f.json._email_type;
        break;
      }
    }
  } catch(e) {}
}
emailType = emailType || 'CategoryC';

const timestamp = Date.now();
const fileName = 'email-image-' + emailId + '-' + timestamp + '.png';

return {
  json: {
    _meta_subject: subject,
    _meta_from: json.From,
    _meta_id: json.id,
    _meta_attachments: json.attachments || [],
    _meta_process_type: 'image',
    _email_type: emailType,
    _image_key: json.image_binary_key || 'attachment_0',
    _s3_filename: fileName
  },
  binary: item.binary
};

// ============================================================
// PREPARE GPT VISION REQUEST FOR IMAGE ATTACHMENTS
// ============================================================

const codeToNameMap = {
  // 'CODE1': 'Full Name 1',
};

const item = $input.item.json;
let meta = {};
try { meta = $('Prepare Image Metadata').first().json; } catch(e) {}

const subject = meta._meta_subject || '';
const emailId = meta._meta_id || '';
const emailType = meta._email_type || 'CategoryC';

const sourceMatch = subject.match(/【([A-Za-z]+)】/i);
const sourceCode = sourceMatch ? sourceMatch[1].toUpperCase() : '';
const sourceName = codeToNameMap[sourceCode] || sourceCode;

const imageUrl = item.Location || '';
if (!imageUrl) return { json: { _skip: true } };

let prompt = '';
if (emailType === 'CategoryA') {
  prompt = 'Subject: ' + subject + '\n\nThis is a CANCELLATION notice.';
} else if (emailType === 'CategoryB') {
  prompt = 'Subject: ' + subject + '\n\nThis is an UPDATE notice.';
} else {
  prompt = 'Subject: ' + subject + '\n\nExtract all relevant data from this image.';
}

const gptBody = {
  model: 'gpt-4o',
  messages: [
    { role: 'system', content: 'You are a data extraction expert. Extract structured information from images.\n\n【Fields】date(YYYY-MM-DD), day_of_week, start_time(HH:MM), end_time(HH:MM), source_code, name, amount(numbers only), category, type, notes\n\n【Output】JSON array only' },
    { role: 'user', content: [{ type: 'text', text: prompt }, { type: 'image_url', image_url: { url: imageUrl, detail: 'high' } }] }
  ],
  max_tokens: 4096
};

return {
  json: {
    _meta_subject: subject,
    _meta_from: meta._meta_from || '',
    _meta_id: emailId,
    _meta_attachments: meta._meta_attachments || [],
    _meta_process_type: 'image',
    _meta_source_name: sourceName,
    _email_type: emailType,
    gpt_request_body: JSON.stringify(gptBody)
  }
};

// ============================================================
// PREPARE GPT REQUEST FOR TEXT-ONLY EMAILS
// ============================================================

const item = $input.item.json;
const subject = item.Subject || '';
const emailId = item.id || '';

let emailType = item._email_type || '';
if (!emailType && emailId) {
  try {
    const filteredItems = $('Filter Valid Emails').all();
    for (const f of filteredItems) {
      if (f.json.id === emailId && f.json._email_type) {
        emailType = f.json._email_type;
        break;
      }
    }
  } catch(e) {}
}
emailType = emailType || 'CategoryC';

const textBody = item.textPlain || item.text || '';
let userPrompt = 'Subject: ' + subject + '\n\nBody:\n' + textBody.substring(0, 3000);
if (emailType === 'CategoryA') userPrompt = '【CANCELLATION】' + userPrompt;
else if (emailType === 'CategoryB') userPrompt = '【UPDATE】' + userPrompt;

const gptBody = {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: 'You are a data extraction expert. Extract structured information from email text.\n\n【Fields】date, day_of_week, start_time, end_time, source_code, name, amount, category, type, notes\n\n【Output】JSON array only' },
    { role: 'user', content: userPrompt }
  ],
  max_tokens: 2048
};

return {
  json: {
    _meta_subject: subject,
    _meta_from: item.From,
    _meta_id: emailId,
    _meta_attachments: item.attachments || [],
    _meta_process_type: 'text',
    _email_type: emailType,
    gpt_request_body: JSON.stringify(gptBody)
  }
};

// ============================================================
// PARSE ALL GPT RESPONSES AND FORMAT FOR OUTPUT
// ============================================================
// Customize the output schema for your Google Sheets
// ============================================================

// Map codes to full names (customize for your use case)
const codeToNameMap = {
  // 'CODE1': 'Full Name 1',
  // 'CODE2': 'Full Name 2',
};

const allItems = $input.all();
const results = [];

let pptxPrepItems = [], imagePrepItems = [], textPrepItems = [];
try { pptxPrepItems = $('Prepare GPT Request (PPTX)').all(); } catch(e) {}
try { imagePrepItems = $('Prepare GPT Request (Image)').all(); } catch(e) {}
try { textPrepItems = $('Prepare GPT Request (Text)').all(); } catch(e) {}

let pptxPrepIndex = 0, imagePrepIndex = 0, textPrepIndex = 0;

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];
  const data = item.json;

  const hasMetadata = !!data._meta_id;
  let subject, from, emailId, attachments, sourceName, emailType;

  if (hasMetadata) {
    subject = data._meta_subject || '';
    from = data._meta_from || '';
    emailId = data._meta_id || '';
    attachments = data._meta_attachments || [];
    sourceName = data._meta_source_name || '';
    emailType = data._email_type || 'CategoryC';
  } else {
    const modelName = data.model || '';
    const isTextModel = modelName.includes('gpt-4o-mini');
    let meta = null;
    if (isTextModel && textPrepIndex < textPrepItems.length) {
      meta = textPrepItems[textPrepIndex].json;
      textPrepIndex++;
    } else if (imagePrepIndex < imagePrepItems.length) {
      meta = imagePrepItems[imagePrepIndex].json;
      imagePrepIndex++;
    } else if (pptxPrepIndex < pptxPrepItems.length) {
      meta = pptxPrepItems[pptxPrepIndex].json;
      pptxPrepIndex++;
    }

    if (meta) {
      subject = meta._meta_subject || '';
      from = meta._meta_from || '';
      emailId = meta._meta_id || '';
      attachments = meta._meta_attachments || [];
      sourceName = meta._meta_source_name || '';
      emailType = meta._email_type || 'CategoryC';
    } else {
      subject = ''; from = ''; emailId = ''; attachments = []; sourceName = ''; emailType = 'CategoryC';
    }
  }

  if (from && typeof from === 'object') {
    from = from.text || from.address || (from.value && from.value[0] ? from.value[0].address : '') || '';
  }
  from = String(from || '');

  let content = '';
  if (data.choices && data.choices[0] && data.choices[0].message) {
    content = data.choices[0].message.content || '';
  }

  // Check for unreadable content
  const unreadablePatterns = ['sorry', 'cannot read', 'unable to', 'not able to'];
  const isUnreadable = unreadablePatterns.some(p => content.toLowerCase().includes(p));

  if (isUnreadable) {
    results.push({
      json: {
        email_type: emailType,
        date: '', day_of_week: '', start_time: '', end_time: '',
        source_name: sourceName, name: '', amount: '0', category: '', type: '',
        status: 'Needs Review', client: '',
        notes: '⚠️File unreadable - manual review required',
        created_at: new Date().toISOString(),
        email_subject: subject, sender: from, email_id: emailId,
        attachments: attachments.map(a => a.filename || '').join(', '),
        _unreadable: true
      }
    });
    continue;
  }

  // Parse JSON from GPT response
  let items = [];
  try {
    let jsonStr = content;
    const codeMatch = content.match(/```json\s*([\s\S]*?)\s*```/);
    if (codeMatch) jsonStr = codeMatch[1];
    else {
      const arrMatch = content.match(/\[[\s\S]*\]/);
      if (arrMatch) jsonStr = arrMatch[0];
    }
    const parsed = JSON.parse(jsonStr);
    items = Array.isArray(parsed) ? parsed : [parsed];
  } catch(e) { 
    if (emailId) {
      results.push({
        json: {
          email_type: emailType,
          date: '', day_of_week: '', start_time: '', end_time: '',
          source_name: sourceName, name: '', amount: '0', category: '', type: '',
          status: 'Needs Review', client: '',
          notes: '⚠️Parse failed - manual review required',
          created_at: new Date().toISOString(),
          email_subject: subject, sender: from, email_id: emailId,
          attachments: attachments.map(a => a.filename || '').join(', '),
          _unreadable: true
        }
      });
    }
    continue;
  }

  if (items.length === 0) continue;

  // ============================================================
  // CUSTOMIZE: Map extracted data to your output schema
  // ============================================================
  for (const s of items) {
    let sourceNameFinal = sourceName || s.source_name || '';
    if (s.source_code) {
      const code = s.source_code.toUpperCase();
      sourceNameFinal = codeToNameMap[code] || sourceNameFinal || code;
    }

    // Determine category from time (customize as needed)
    let category = s.category || '';
    if (!category && s.start_time) {
      const h = parseInt(s.start_time.split(':')[0]) || 0;
      if (h >= 5 && h < 10) category = 'Morning';
      else if (h >= 10 && h < 15) category = 'Afternoon';
      else if (h >= 15 && h < 23) category = 'Evening';
      else category = 'Night';
    }

    results.push({
      json: {
        email_type: emailType,
        date: s.date || '',
        day_of_week: s.day_of_week || '',
        start_time: s.start_time || '',
        end_time: s.end_time || '',
        source_name: sourceNameFinal,
        name: s.name || '',
        amount: String(s.amount || 0),
        category: category,
        type: s.type || 'Regular',
        status: 'Pending',
        client: '',
        notes: s.notes || '',
        created_at: new Date().toISOString(),
        email_subject: subject,
        sender: from,
        email_id: emailId,
        attachments: attachments.map(a => a.filename || '').join(', ')
      }
    });
  }
}

if (results.length === 0) return [{ json: { _no_data: true } }];
return results;

