const allItems = $input.all();
const emailMap = new Map();

function addEmail(emailId, emailType, isUnreadable) {
  if (!emailId) return;
  if (!emailMap.has(emailId)) {
    emailMap.set(emailId, { type: isUnreadable ? 'NeedsReview' : emailType });
  }
  if (isUnreadable) emailMap.get(emailId).type = 'NeedsReview';
}

for (const item of allItems) {
  const emailId = item.json.email_id;
  const emailType = item.json.email_type || 'CategoryC';
  const isUnreadable = item.json._unreadable === true;
  addEmail(emailId, emailType, isUnreadable);
}

try {
  const filteredItems = $('Filter Valid Emails').all();
  for (const f of filteredItems) {
    addEmail(f.json.id, f.json._email_type || 'CategoryC', false);
  }
} catch (e) {}

return Array.from(emailMap.entries()).map(([id, data]) => ({
  json: { email_id: id, email_type: data.type }
}));

